import { useParams } from "react-router-dom";
import { useEffect, useState } from "react";
import "./Article.css";

function formatDateKa(dateStr) {
  const months = [
    "იანვარი","თებერვალი","მარტი","აპრილი","მაისი","ივნისი",
    "ივლისი","აგვისტო","სექტემბერი","ოქტომბერი","ნოემბერი","დეკემბერი"
  ];
  const d = new Date(dateStr);
  return `${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`;
}

export default function ArticleDetail() {
  const { slug } = useParams();
  const [article, setArticle] = useState(null);
  const [user, setUser] = useState(false);
  const [saved, setSaved] = useState([]);

  useEffect(() => {
    fetch(`http://localhost:5000/api/articles/${slug}`)
      .then(res => res.json())
      .then(data => setArticle(data))
      .catch(err => console.error("FETCH ERROR:", err));

    const token = localStorage.getItem("auth_token");
    if (token) setUser(true);

    const savedArticles =
      JSON.parse(localStorage.getItem("savedArticles")) || [];
    setSaved(savedArticles);
  }, [slug]);

  if (!article) return <p>იტვირთება...</p>;

  const isSaved = saved.find(a => a.slug === article.slug);

  const toggleSave = () => {
    let updated;

    if (isSaved) {
      updated = saved.filter(a => a.slug !== article.slug);
    } else {
      updated = [...saved, article];
    }

    setSaved(updated);
    localStorage.setItem("savedArticles", JSON.stringify(updated));
  };

  return (
    <div className="article-page">
      <div className="article-container" style={{ position: "relative" }}>

        {user && (
          <img
            src={isSaved ? "/public/save1.png" : "/images/save.png"}
            className="save-icon-article"
            onClick={toggleSave}
            alt="save"
          />
        )}

        <h1 className="article-title">{article.title}</h1>

        <img
          src={`http://localhost:5000${article.image}`}
          alt={article.title}
          className="article-hero"
        />

        <p style={{
          color: "#6d6d6db6",
          fontSize: "14px",
          textAlign: "center",
          marginBottom: "30px"
        }}>
          {formatDateKa(article.date)}
        </p>

        <div
          className="lead"
          dangerouslySetInnerHTML={{ __html: article.html }}
        />
      </div>
    </div>
  );
}
